# Create full-stack Inventory Management System project structure
import os
import zipfile
from pathlib import Path

base_path = Path("/mnt/data/inventory-management-system")
backend_path = base_path / "backend"
frontend_path = base_path / "frontend"

# Create directories
(backend_path / "src").mkdir(parents=True, exist_ok=True)
(frontend_path / "src").mkdir(parents=True, exist_ok=True)
(frontend_path / "public").mkdir(parents=True, exist_ok=True)

# -----------------------
# Backend Files
# -----------------------

backend_package_json = """
{
  "name": "inventory-backend",
  "version": "1.0.0",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "pg": "^8.11.3",
    "cors": "^2.8.5"
  }
}
"""

server_js = """
const express = require("express");
const cors = require("cors");
const { Pool } = require("pg");

const app = express();
app.use(cors());
app.use(express.json());

const pool = new Pool({
  host: process.env.DB_HOST || "db",
  user: process.env.POSTGRES_USER || "postgres",
  password: process.env.POSTGRES_PASSWORD || "postgres",
  database: process.env.POSTGRES_DB || "inventory",
  port: 5432,
});

app.get("/api/stock", async (req, res) => {
  const { rows } = await pool.query("SELECT * FROM products ORDER BY id");
  res.json(rows);
});

app.post("/api/stock/deduct/:id", async (req, res) => {
  const client = await pool.connect();
  try {
    await client.query("BEGIN");
    const { id } = req.params;
    const result = await client.query(
      "SELECT stock FROM products WHERE id = $1 FOR UPDATE",
      [id]
    );
    if (result.rowCount === 0) throw new Error("Product not found");

    const stock = result.rows[0].stock;
    if (stock <= 0) throw new Error("Out of stock");

    await client.query(
      "UPDATE products SET stock = stock - 1 WHERE id = $1",
      [id]
    );

    await client.query("COMMIT");
    res.json({ message: "Stock deducted successfully" });
  } catch (err) {
    await client.query("ROLLBACK");
    res.status(400).json({ error: err.message });
  } finally {
    client.release();
  }
});

app.post("/api/stock/restore/:id", async (req, res) => {
  const { id } = req.params;
  await pool.query("UPDATE products SET stock = stock + 1 WHERE id = $1", [id]);
  res.json({ message: "Stock restored" });
});

app.listen(5000, () => console.log("Backend running on port 5000"));
"""

schema_sql = """
CREATE TABLE IF NOT EXISTS products (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  stock INTEGER NOT NULL CHECK (stock >= 0)
);

INSERT INTO products (name, stock)
VALUES ('Product A', 10),
       ('Product B', 3)
ON CONFLICT DO NOTHING;
"""

# Write backend files
(backend_path / "package.json").write_text(backend_package_json)
(backend_path / "src/server.js").write_text(server_js)
(backend_path / "init.sql").write_text(schema_sql)

# -----------------------
# Frontend Files
# -----------------------

frontend_package_json = """
{
  "name": "inventory-frontend",
  "version": "1.0.0",
  "private": true,
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1",
    "axios": "^1.6.2"
  },
  "scripts": {
    "start": "react-scripts start"
  }
}
"""

index_html = """
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8" />
  <title>Inventory Dashboard</title>
</head>
<body>
  <div id="root"></div>
</body>
</html>
"""

app_js = """
import React, { useEffect, useState } from "react";
import axios from "axios";

function App() {
  const [products, setProducts] = useState([]);

  const fetchStock = async () => {
    const res = await axios.get("http://localhost:5000/api/stock");
    setProducts(res.data);
  };

  const deduct = async (id) => {
    await axios.post(`http://localhost:5000/api/stock/deduct/${id}`);
    fetchStock();
  };

  const restore = async (id) => {
    await axios.post(`http://localhost:5000/api/stock/restore/${id}`);
    fetchStock();
  };

  useEffect(() => {
    fetchStock();
  }, []);

  return (
    <div>
      <h1>Inventory Dashboard</h1>
      {products.map((p) => (
        <div key={p.id}>
          <strong>{p.name}</strong> - Stock: {p.stock}
          {p.stock <= 5 && <span style={{color:"red"}}> LOW STOCK</span>}
          <button onClick={() => deduct(p.id)}>Deduct</button>
          <button onClick={() => restore(p.id)}>Restore</button>
        </div>
      ))}
    </div>
  );
}

export default App;
"""

index_js = """
import React from "react";
import { createRoot } from "react-dom/client";
import App from "./App";

const root = createRoot(document.getElementById("root"));
root.render(<App />);
"""

# Write frontend files
(frontend_path / "package.json").write_text(frontend_package_json)
(frontend_path / "public/index.html").write_text(index_html)
(frontend_path / "src/App.js").write_text(app_js)
(frontend_path / "src/index.js").write_text(index_js)

# -----------------------
# Docker & Compose
# -----------------------

docker_backend = """
FROM node:18
WORKDIR /app
COPY package*.json ./
RUN npm install
COPY . .
EXPOSE 5000
CMD ["npm", "start"]
"""

docker_frontend = """
FROM node:18
WORKDIR /app
COPY package*.json ./
RUN npm install
COPY . .
EXPOSE 3000
CMD ["npm", "start"]
"""

docker_compose = """
services:
  db:
    image: postgres:15
    environment:
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      POSTGRES_DB: inventory
    volumes:
      - db_data:/var/lib/postgresql/data
      - ./backend/init.sql:/docker-entrypoint-initdb.d/init.sql
    ports:
      - "5432:5432"

  backend:
    build: ./backend
    ports:
      - "5000:5000"
    depends_on:
      - db
    environment:
      DB_HOST: db
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      POSTGRES_DB: inventory

  frontend:
    build: ./frontend
    ports:
      - "3000:3000"
    depends_on:
      - backend

volumes:
  db_data:
"""

readme = """
# Inventory Management System

## Run Instructions

docker compose up --build

Access:
Frontend: http://localhost:3000
Backend: http://localhost:5000

## Verification

### Low Stock Alert
Product B starts with stock = 3.
Dashboard shows LOW STOCK label when stock <= 5.

### Race Condition Test
Open 5 browser tabs and click deduct simultaneously.
Because of SELECT ... FOR UPDATE inside transaction,
overselling is prevented and stock never goes negative.
"""

(base_path / "backend/Dockerfile").write_text(docker_backend)
(base_path / "frontend/Dockerfile").write_text(docker_frontend)
(base_path / "docker-compose.yml").write_text(docker_compose)
(base_path / "README.md").write_text(readme)

# -----------------------
# Zip everything
# -----------------------

zip_path = "/mnt/data/inventory-management-system.zip"
with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zipf:
    for file_path in base_path.rglob("*"):
        zipf.write(file_path, file_path.relative_to(base_path))

zip_path

